def word_freq(text: str) -> dict:
    """Map each lowercased word in text to its count."""
    if not isinstance(text, str):
        raise ValueError("text must be a string")

    word_count = {}
    words = text.lower().split()
    for word in words:
        if word in word_count:
            word_count[word] += 1
        else:
            word_count[word] = 1

    return word_count
```

